import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { CONTEXT_MENU_CONTEXT, type ContextMenuContext } from './context-menu.tokens';

let _contextMenuIdCounter = 0;

@Component({
  selector: 'n-context-menu',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: CONTEXT_MENU_CONTEXT,
      useFactory: (cmp: ContextMenuComponent) => cmp.context,
      deps: [forwardRef(() => ContextMenuComponent)],
    },
  ],
})
export class ContextMenuComponent {
  readonly nOpen = model<boolean>(false);
  readonly nId = input<string>('');

  readonly nOpenChange = output<boolean>();

  private readonly _staticId = `n-context-menu-${++_contextMenuIdCounter}`;
  private readonly _cursorX = signal(0);
  private readonly _cursorY = signal(0);

  readonly rootId = computed(() => this.nId() || this._staticId);

  readonly context: ContextMenuContext = Object.create(null);

  constructor() {
    Object.assign(this.context, {
      open: this.nOpen,
      cursorX: this._cursorX,
      cursorY: this._cursorY,
      openAt: (x: number, y: number) => {
        this._cursorX.set(x);
        this._cursorY.set(y);
        this._setOpen(true);
      },
      close: () => {
        this._setOpen(false);
      },
    });
    Object.defineProperty(this.context, 'contentId', {
      get: () => `${this.rootId()}-content`,
    });
  }

  private _setOpen(value: boolean): void {
    if (this.nOpen() === value) return;
    this.nOpen.set(value);
    this.nOpenChange.emit(value);
  }
}

import { InjectionToken, Signal, WritableSignal } from '@angular/core';

export interface ContextMenuContext {
  readonly open: WritableSignal<boolean>;
  readonly cursorX: WritableSignal<number>;
  readonly cursorY: WritableSignal<number>;
  readonly contentId: string;
  openAt(x: number, y: number): void;
  close(restoreFocus?: boolean): void;
}

export const CONTEXT_MENU_CONTEXT = new InjectionToken<ContextMenuContext>('CONTEXT_MENU_CONTEXT');

export interface ContextMenuSubContext {
  readonly open: WritableSignal<boolean>;
  readonly triggerEl: Signal<HTMLElement | null>;
  readonly contentId: string;
  readonly triggerId: string;
  readonly parent: ContextMenuContext;
  setTriggerEl(el: HTMLElement | null): void;
  toggle(): void;
  openMenu(): void;
  close(focusTrigger?: boolean): void;
}

export const CONTEXT_MENU_SUB_CONTEXT = new InjectionToken<ContextMenuSubContext>(
  'CONTEXT_MENU_SUB_CONTEXT',
);

export interface ContextMenuRadioGroupContext {
  readonly value: WritableSignal<string | null>;
  select(value: string): void;
}

export const CONTEXT_MENU_RADIO_GROUP_CONTEXT =
  new InjectionToken<ContextMenuRadioGroupContext>('CONTEXT_MENU_RADIO_GROUP_CONTEXT');

import { cva, type VariantProps } from 'class-variance-authority';

export const contextMenuContentVariants = cva(
  [
    'z-50 min-w-[8rem] overflow-hidden rounded-md border bg-popover p-1 text-popover-foreground shadow-md',
    'animate-in fade-in-0 zoom-in-95',
  ],
  {
    variants: {
      nSize: {
        sm: 'text-xs',
        default: 'text-sm',
      },
    },
    defaultVariants: { nSize: 'default' },
  },
);

export type ContextMenuContentVariants = VariantProps<typeof contextMenuContentVariants>;

export const contextMenuItemVariants = cva(
  [
    'relative flex cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 outline-none transition-colors',
    'data-[highlighted]:bg-accent data-[highlighted]:text-accent-foreground',
    'data-[disabled]:pointer-events-none data-[disabled]:opacity-50',
    '[&_svg]:size-4 [&_svg]:shrink-0',
  ],
  {
    variants: {
      nVariant: {
        default: '',
        destructive:
          'text-destructive data-[highlighted]:bg-destructive data-[highlighted]:text-destructive-foreground',
      },
      nInset: {
        true: 'pl-8',
        false: '',
      },
    },
    defaultVariants: { nVariant: 'default', nInset: false },
  },
);

export type ContextMenuItemVariants = VariantProps<typeof contextMenuItemVariants>;

import { Directive, ElementRef, inject } from '@angular/core';
import { CONTEXT_MENU_CONTEXT } from './context-menu.tokens';

@Directive({
  selector: '[n-context-menu-trigger]',
  standalone: true,
  host: {
    'data-slot': 'trigger',
    'aria-haspopup': 'menu',
    '[attr.data-state]': 'ctx.open() ? "open" : "closed"',
    '(contextmenu)': 'handleContextMenu($event)',
    '(keydown)': 'handleKeydown($event)',
  },
})
export class ContextMenuTriggerDirective {
  protected readonly ctx = inject(CONTEXT_MENU_CONTEXT);
  private readonly _host = inject<ElementRef<HTMLElement>>(ElementRef);

  protected handleContextMenu(event: MouseEvent): void {
    event.preventDefault();
    this.ctx.openAt(event.clientX, event.clientY);
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key === 'F10' && event.shiftKey) {
      event.preventDefault();
      const rect = this._host.nativeElement.getBoundingClientRect();
      this.ctx.openAt(rect.left, rect.bottom);
    }
  }
}

import { FocusKeyManager } from '@angular/cdk/a11y';
import {
  GlobalPositionStrategy,
  Overlay,
  OverlayConfig,
  OverlayRef,
} from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
