export class ContextMenuSubTriggerComponent implements OnDestroy {
  readonly nInset = input<boolean>(false);
  readonly nDisabled = input<boolean>(false);
  readonly nClass = input<string>('');

  protected readonly ctx = inject(CONTEXT_MENU_SUB_CONTEXT);
  private readonly _host = inject<ElementRef<HTMLElement>>(ElementRef);

  constructor() {
    this.ctx.setTriggerEl(this._host.nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
  }

  protected readonly classes = computed(() =>
    mergeClasses(
      contextMenuItemVariants({ nVariant: 'default', nInset: this.nInset() }),
      'data-[state=open]:bg-accent data-[state=open]:text-accent-foreground',
      this.nClass(),
    ),
  );

  protected handleClick(event: MouseEvent): void {
    if (this.nDisabled()) return;
    event.preventDefault();
    event.stopPropagation();
    this.ctx.toggle();
  }

  protected handleEnter(): void {
    if (this.nDisabled()) return;
    this.ctx.openMenu();
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (this.nDisabled()) return;
    if (event.key === 'ArrowRight' || event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      this.ctx.openMenu();
    }
  }
}

